const event = msg.req && msg.req.params && msg.req.params.event;
const data = msg.payload;

if (!event || !data) {
    msg.payload = { success: false, error: "Invalid payload" };
    msg.statusCode = 400;
    return [msg, null];
}

// Respond 200 immediately to Invoice Ninja to acknowledge receipt
const responseMsg = {
    payload: { success: true },
    statusCode: 200,
    headers: { "Content-Type": "application/json" },
    req: msg.req,
    res: msg.res
};

// For invoice/quote events, validate required fields
if (/^(create|update)_(invoice|quote)$/i.test(event)) {
    if (data.client_id === undefined || data.status_id === undefined) {
        node.warn(`CurbClass: Ignoring ${event} webhook missing client_id/status_id`);
        return [responseMsg, null];
    }
}

const jobMsg = { token: env.get("CURBCLASS_TWENTY_TOKEN"), ninjaEvent: event, ninjaData: data };
return [responseMsg, jobMsg];

const client = msg.ninjaData;
const clientId = client.hashed_id || client.id;
const primaryContact = client.contacts && client.contacts[0];
const email = primaryContact ? (primaryContact.email || "").trim().toLowerCase() : "";
const name = client.name || (primaryContact ? `${primaryContact.first_name} ${primaryContact.last_name}` : "");

if (!email) {
    return null; // Can not map without email
}

const nameParts = name.trim().split(" ");
const firstName = nameParts[0] || "";
const lastName = nameParts.slice(1).join(" ");

msg.clientInfo = {
    id: clientId,
    firstName: firstName,
    lastName: lastName,
    email: email
};

msg.method = "GET";
msg.url = `${env.get("TWENTY_BASE_URL")}/rest/people?filter=emails.primaryEmail[eq]:${encodeURIComponent(email)}`;
msg.headers = {
    "Authorization": "Bearer " + msg.token,
    "Host": "curbclass.localhost:3000"
};

return msg;

const searchData = msg.payload;
const existingPerson = searchData.data && searchData.data.people && searchData.data.people[0];
let url, method, body;

if (existingPerson) {
    url = `${env.get("TWENTY_BASE_URL")}/rest/people/${existingPerson.id}`;
    method = "PATCH";
    body = {
        invoiceNinjaClientId: msg.clientInfo.id
    };
} else {
    url = env.get("TWENTY_BASE_URL") + "/rest/people";
    method = "POST";
    body = {
        name: {
            firstName: msg.clientInfo.firstName,
            lastName: msg.clientInfo.lastName
        },
        emails: {
            primaryEmail: msg.clientInfo.email
        },
        jobTitle: "Curb Class Client",
        invoiceNinjaClientId: msg.clientInfo.id
    };
}

msg.method = method;
msg.url = url;
msg.payload = body;
msg.headers = {
    "Authorization": "Bearer " + msg.token,
    "Host": "curbclass.localhost:3000",
    "Content-Type": "application/json"
};

return msg;

const invoice = msg.ninjaData;
const clientHashedId = invoice.client_id;
const invoiceStatusId = invoice.status_id;
const invoiceAmount = invoice.amount;

// We need to find the person in Twenty who matches clientHashedId
msg.invoiceInfo = {
    statusId: invoiceStatusId,
    amount: invoiceAmount,
    balance: invoice.balance,
    number: invoice.number,
    invoiceId: invoice.id || invoice.hashed_id,
    clientHashedId: clientHashedId
};

msg.method = "GET";
msg.url = `${env.get("TWENTY_BASE_URL")}/rest/people?filter=invoiceNinjaClientId[eq]:${encodeURIComponent(clientHashedId)}`;
msg.headers = {
    "Authorization": "Bearer " + msg.token,
    "Host": "curbclass.localhost:3000"
};

return msg;

const searchData = msg.payload;
const person = searchData.data && searchData.data.people && searchData.data.people[0];
if (!person) {
    node.warn("CurbClass: Could not find Person in Twenty with Client ID: " + msg.invoiceInfo.clientHashedId);
    return null;
}

msg.personId = person.id;

// Next, find the latest Opportunity for this Person to update its stage
msg.method = "GET";
msg.url = `${env.get("TWENTY_BASE_URL")}/rest/opportunities?filter=pointOfContactId[eq]:${encodeURIComponent(person.id)}`;
msg.headers = {
    "Authorization": "Bearer " + msg.token,
    "Host": "curbclass.localhost:3000"
};

return msg;

const searchData = msg.payload;
const opportunities = searchData.data && searchData.data.opportunities;
if (!opportunities || opportunities.length === 0) {
    node.warn("CurbClass: No Opportunity found for Person ID: " + msg.personId);
    return null;
}

const invoiceId = String(msg.invoiceInfo.invoiceId);

// Exact-match: find an opportunity that already has this invoice ID in invoiceNinjaRefs
const exactMatch = opportunities.find(o => {
    try {
        const refs = o.invoiceNinjaRefs ? JSON.parse(o.invoiceNinjaRefs) : [];
        return refs.includes(invoiceId);
    } catch (e) { return false; }
});

let opp;
let needsWriteback = false;

if (exactMatch) {
    opp = exactMatch;
} else {
    // Heuristic fallback (first-sighting): prefer open, most recently updated
    const openOpps = opportunities.filter(o => o.stage !== "CUSTOMER");
    const candidates = openOpps.length > 0 ? openOpps : opportunities;
    candidates.sort((a, b) => new Date(b.updatedAt) - new Date(a.updatedAt));
    opp = candidates[0];
    if (openOpps.length > 1) {
        node.warn(`CurbClass: Person ${msg.personId} has ${openOpps.length} open opportunities; picked most recently updated (${opp.id}) for invoice ${invoiceId}.`);
    }
    needsWriteback = true;
}

msg.opportunityId = opp.id;

// Status IDs in Invoice Ninja: 1=Draft, 2=Sent, 3=Viewed, 4=Paid, etc.
const ninjaStatus = msg.invoiceInfo.statusId;
let stage = opp.stage;
if (ninjaStatus === "4" || ninjaStatus === 4) {
    stage = "CUSTOMER";
} else if (ninjaStatus === "2" || ninjaStatus === 2 || ninjaStatus === "3" || ninjaStatus === 3) {
    stage = "PROPOSAL";
}

msg.method = "PATCH";
msg.url = `${env.get("TWENTY_BASE_URL")}/rest/opportunities/${opp.id}`;
msg.payload = { stage: stage };

// Writeback: add invoiceId to invoiceNinjaRefs if this is the first sighting
if (needsWriteback) {
    try {
        const refs = opp.invoiceNinjaRefs ? JSON.parse(opp.invoiceNinjaRefs) : [];
        if (!refs.includes(invoiceId)) {
            refs.push(invoiceId);
            msg.payload.invoiceNinjaRefs = JSON.stringify(refs);
        }
    } catch (e) {
        msg.payload.invoiceNinjaRefs = JSON.stringify([invoiceId]);
    }
}

msg.headers = {
    "Authorization": "Bearer " + msg.token,
    "Host": "curbclass.localhost:3000",
    "Content-Type": "application/json"
};

return msg;

const info = msg.invoiceInfo;
const statusLabels = { "1": "Draft", "2": "Sent", "3": "Viewed", "4": "Paid", "5": "Partial", "6": "Cancelled" };
const statusLabel = statusLabels[String(info.statusId)] || `Status ${info.statusId}`;
const invoiceUrl = `https://invoice.cosmoslab.dev/invoices/${info.invoiceId}`;
const displayNumber = info.number || info.invoiceId;

msg.noteTitle = `Invoice #${displayNumber} - ${statusLabel}`;
msg.noteMarkdown = `[View Invoice #${displayNumber} in Invoice Ninja](${invoiceUrl})`;

msg.twentyToken = msg.token;
msg.twentyHost = "curbclass.localhost:3000";

return msg;

const quote = msg.ninjaData;
const clientHashedId = quote.client_id;
const quoteStatusId = quote.status_id;
const quoteAmount = quote.amount;

msg.quoteInfo = {
    statusId: quoteStatusId,
    amount: quoteAmount,
    balance: quote.balance,
    number: quote.number,
    quoteId: quote.id || quote.hashed_id,
    clientHashedId: clientHashedId
};

msg.method = "GET";
msg.url = `${env.get("TWENTY_BASE_URL")}/rest/people?filter=invoiceNinjaClientId[eq]:${encodeURIComponent(clientHashedId)}`;
msg.headers = {
    "Authorization": "Bearer " + msg.token,
    "Host": "curbclass.localhost:3000"
};

return msg;

const searchData = msg.payload;
const person = searchData.data && searchData.data.people && searchData.data.people[0];
if (!person) {
    node.warn("CurbClass: Could not find Person in Twenty with Client ID: " + msg.quoteInfo.clientHashedId);
    return null;
}

msg.personId = person.id;

// Next, find the latest Opportunity for this Person to update its stage
msg.method = "GET";
msg.url = `${env.get("TWENTY_BASE_URL")}/rest/opportunities?filter=pointOfContactId[eq]:${encodeURIComponent(person.id)}`;
msg.headers = {
    "Authorization": "Bearer " + msg.token,
    "Host": "curbclass.localhost:3000"
};

return msg;

const searchData = msg.payload;
const opportunities = searchData.data && searchData.data.opportunities;
if (!opportunities || opportunities.length === 0) {
    node.warn("CurbClass: No Opportunity found for Person ID: " + msg.personId);
    return null;
}

const quoteId = String(msg.quoteInfo.quoteId);

// Exact-match: find an opportunity that already has this quote ID in invoiceNinjaRefs
const exactMatch = opportunities.find(o => {
    try {
        const refs = o.invoiceNinjaRefs ? JSON.parse(o.invoiceNinjaRefs) : [];
        return refs.includes(quoteId);
    } catch (e) { return false; }
});

let opp;
let needsWriteback = false;

if (exactMatch) {
    opp = exactMatch;
} else {
    // Heuristic fallback (first-sighting): prefer open, most recently updated
    const openOpps = opportunities.filter(o => o.stage !== "CUSTOMER");
    const candidates = openOpps.length > 0 ? openOpps : opportunities;
    candidates.sort((a, b) => new Date(b.updatedAt) - new Date(a.updatedAt));
    opp = candidates[0];
    if (openOpps.length > 1) {
        node.warn(`CurbClass: Person ${msg.personId} has ${openOpps.length} open opportunities; picked most recently updated (${opp.id}) for quote ${quoteId}.`);
    }
    needsWriteback = true;
}

msg.opportunityId = opp.id;

// Quote status IDs: 1=Draft, 2=Sent, 3=Approved, 4=Converted, 5=Expired
const ninjaStatus = msg.quoteInfo.statusId;
let stage = opp.stage;
if (ninjaStatus === "1" || ninjaStatus === 1) {
    stage = "MEETING";
} else if (ninjaStatus === "2" || ninjaStatus === 2 || ninjaStatus === "3" || ninjaStatus === 3) {
    stage = "PROPOSAL";
}

msg.method = "PATCH";
msg.url = `${env.get("TWENTY_BASE_URL")}/rest/opportunities/${opp.id}`;
msg.payload = { stage: stage };

// Writeback: add quoteId to invoiceNinjaRefs if this is the first sighting
if (needsWriteback) {
    try {
        const refs = opp.invoiceNinjaRefs ? JSON.parse(opp.invoiceNinjaRefs) : [];
        if (!refs.includes(quoteId)) {
            refs.push(quoteId);
            msg.payload.invoiceNinjaRefs = JSON.stringify(refs);
        }
    } catch (e) {
        msg.payload.invoiceNinjaRefs = JSON.stringify([quoteId]);
    }
}

msg.headers = {
    "Authorization": "Bearer " + msg.token,
    "Host": "curbclass.localhost:3000",
    "Content-Type": "application/json"
};

return msg;

const info = msg.quoteInfo;
const statusLabels = { "1": "Draft", "2": "Sent", "3": "Approved", "4": "Converted", "5": "Expired" };
const statusLabel = statusLabels[String(info.statusId)] || `Status ${info.statusId}`;
const quoteUrl = `https://invoice.cosmoslab.dev/quotes/${info.quoteId}`;
const displayNumber = info.number || info.quoteId;

msg.noteTitle = `Quote #${displayNumber} - ${statusLabel}`;
msg.noteMarkdown = `[View Quote #${displayNumber} in Invoice Ninja](${quoteUrl})`;

msg.twentyToken = msg.token;
msg.twentyHost = "curbclass.localhost:3000";

return msg;

msg.method = "GET";
msg.url = `${env.get("TWENTY_BASE_URL")}/rest/notes?filter=title[eq]:${encodeURIComponent(msg.noteTitle)}`;
msg.headers = {
    "Authorization": "Bearer " + msg.twentyToken,
    "Host": msg.twentyHost
};
return msg;

const notes = msg.payload && msg.payload.data && msg.payload.data.notes;
if (notes && notes.length > 0) {
    node.warn("CurbClass: Skipping duplicate note - already exists: " + msg.noteTitle);
    return null;
}
return msg;

msg.method = "GET";
msg.url = "http://bodhi.lab:9280/api/v1/clients?per_page=100&page=1";
msg.headers = {
    "X-Api-Token": env.get("CURBCLASS_INVOICENINJA_TOKEN"),
    "Accept": "application/json"
};
return msg;

const clients = (msg.payload && msg.payload.data) || [];
const pagination = msg.payload && msg.payload.meta && msg.payload.meta.pagination;
if (pagination && pagination.total_pages > 1) {
    node.warn(`CurbClass Reconciliation: Invoice Ninja has ${pagination.total_pages} pages of clients, only checking page 1 (per_page=100)`);
}

const token = env.get("CURBCLASS_TWENTY_TOKEN");
const msgs = [];
for (const client of clients) {
    if (client.is_deleted) continue;
    const contact = client.contacts && client.contacts[0];
    const email = contact && contact.email;
    if (!email) continue;

    const m = {};
    m.ninjaClientId = client.id;
    m.method = "GET";
    m.url = `${env.get("TWENTY_BASE_URL")}/rest/people?filter=emails.primaryEmail[eq]:${encodeURIComponent(email)}`;
    m.headers = {
        "Authorization": "Bearer " + token,
        "Host": "curbclass.localhost:3000"
    };
    msgs.push(m);
}
return [msgs];

const people = msg.payload && msg.payload.data && msg.payload.data.people;
const person = people && people[0];
if (!person || person.invoiceNinjaClientId) {
    return null; // no match, or already linked
}

node.warn(`CurbClass Reconciliation: Backfilling invoiceNinjaClientId=${msg.ninjaClientId} for person ${person.id}`);

msg.method = "PATCH";
msg.url = `${env.get("TWENTY_BASE_URL")}/rest/people/${person.id}`;
msg.payload = { invoiceNinjaClientId: msg.ninjaClientId };
return msg;

delete msg.res;
delete msg.req;

const person = msg.payload && msg.payload.data && (msg.payload.data.createPerson || msg.payload.data.updatePerson);
if (!person) {
    return null;
}

const email = person.emails ? (person.emails.primaryEmail || '') : '';
const firstName = person.name ? (person.name.firstName || '') : '';
const lastName = person.name ? (person.name.lastName || '') : '';
const name = `${firstName} ${lastName}`.trim();

if (person.invoiceNinjaClientId || !email) {
    return null;
}

msg.personId = person.id;
msg.method = "POST";
msg.url = "http://bodhi.lab:9280/api/v1/clients";
msg.payload = {
    name: name,
    contacts: [
        {
            first_name: firstName,
            last_name: lastName,
            email: email,
            send_email: true
        }
    ]
};
msg.headers = {
    "X-Api-Token": env.get("CURBCLASS_INVOICENINJA_TOKEN"),
    "Content-Type": "application/json",
    "Accept": "application/json"
};

return msg;

const client = msg.payload && msg.payload.data;
const clientId = client ? (client.hashed_id || client.id) : '';

if (!clientId) {
    node.warn("CurbClass: Failed to create client in Invoice Ninja");
    return null;
}

msg.method = "PATCH";
msg.url = `${env.get("TWENTY_BASE_URL")}/rest/people/${msg.personId}`;
msg.payload = {
    invoiceNinjaClientId: clientId
};

return msg;
